// Realiza o match regional e de categorias entre a vaga e os candidatos em Tempo Real
const usuarios = $node["Listar Usuários Tempo Real"].json.id ? $node["Listar Usuários Tempo Real"].json : $input.all().map(i => i.json);
const vagas = $node["Listar Vagas Novas"].json.id ? [$node["Listar Vagas Novas"].json] : [];

if (usuarios.length === 0 || vagas.length === 0) {
  return [];
}

const disparos = [];

vagas.forEach(vaga => {
  usuarios.forEach(user => {
    // 1. Validar match regional (cidade correta ou vaga remota)
    const matchLocal = vaga.localidade.toLowerCase().includes('remoto') || 
                       (user.cidade && vaga.localidade.toLowerCase().includes(user.cidade.toLowerCase()));

    if (!matchLocal) return;

    // 2. Validar match de categoria/interesse
    // Buscamos se as palavras-chave da vaga batem com o interesse do usuario
    const interesses = (user.categorias_vagas || '').split(',');
    let matchCategoria = interesses.length === 0 || user.categorias_vagas === '';

    interesses.forEach(int => {
      if (vaga.titulo.toLowerCase().includes(int.toLowerCase()) || 
          vaga.descricao.toLowerCase().includes(int.toLowerCase())) {
        matchCategoria = true;
      }
    });

    if (matchCategoria) {
      disparos.push({
        json: {
          usuario_id: user.id,
          vaga_id: vaga.id,
          nome_usuario: user.nome,
          whatsapp: user.whatsapp,
          titulo_vaga: vaga.titulo,
          empresa: vaga.empresa,
          url_vaga: vaga.url,
          localidade: vaga.localidade,
          data_envio: new Date().toISOString()
        }
      });
    }
  });
});

return disparos;

// Simulação de envio do alerta de vaga em tempo real via WhatsApp
const item = $input.first().json;
const msg = `⚡ **Nova Vaga Encontrada!**\n\nOlá, ${item.nome_usuario}! Uma vaga compatível com seu perfil acaba de ser publicada:\n\n📌 **${item.titulo_vaga}**\n🏢 Empresa: ${item.empresa}\n📍 Local: ${item.localidade}\n\n🔗 Inscreva-se aqui: ${item.url_vaga}`;

console.log('====================================');
console.log(`[WHATSAPP REALTIME] ENVIADO PARA: ${item.whatsapp}`);
console.log(msg);
console.log('====================================');

return {
  usuario_id: item.usuario_id,
  vaga_id: item.vaga_id,
  whatsapp: item.whatsapp,
  message: msg
};

// Compila o resumo de vagas do dia para cada usuário de acordo com região e interesse
const usuarios = $node["Buscar Usuários Diário"].json.id ? $node["Buscar Usuários Diário"].json : $input.all().map(i => i.json);
const vagas = $node["Buscar Vagas das últimas 24h"].json.id ? [$node["Buscar Vagas das últimas 24h"].json] : [];

if (usuarios.length === 0 || vagas.length === 0) {
  return [];
}

const consolidado = [];

usuarios.forEach(user => {
  const vagasCompativeis = [];

  vagas.forEach(vaga => {
    // Match regional
    const matchLocal = vaga.localidade.toLowerCase().includes('remoto') || 
                       (user.cidade && vaga.localidade.toLowerCase().includes(user.cidade.toLowerCase()));
    if (!matchLocal) return;

    // Match categoria
    const interesses = (user.categorias_vagas || '').split(',');
    let matchCategoria = interesses.length === 0 || user.categorias_vagas === '';
    interesses.forEach(int => {
      if (vaga.titulo.toLowerCase().includes(int.toLowerCase())) {
        matchCategoria = true;
      }
    });

    if (matchCategoria) {
      vagasCompativeis.push(vaga);
    }
  });

  if (vagasCompativeis.length > 0) {
    consolidado.push({
      json: {
        usuario_id: user.id,
        nome_usuario: user.nome,
        whatsapp: user.whatsapp,
        vagas: vagasCompativeis
      }
    });
  }
});

return consolidado;

// Formata a mensagem de resumo diario com a lista de vagas encontradas
const item = $input.first().json;

let listaVagas = '';
item.vagas.forEach((v, index) => {
  listaVagas += `\n${index + 1}. 📌 *${v.titulo}*\n   🏢 ${v.empresa} (${v.localidade})\n   🔗 Link: ${v.url}\n`;
});

const msg = `📅 **Seu Resumo Diário de Vagas JAB**\n\nOlá, ${item.nome_usuario}! Encontramos as seguintes oportunidades compatíveis hoje:\n${listaVagas}\nBoa sorte na sua busca! 🚀`;

console.log('====================================');
console.log(`[WHATSAPP DIARIO] ENVIADO PARA: ${item.whatsapp}`);
console.log(msg);
console.log('====================================');

return {
  usuario_id: item.usuario_id,
  whatsapp: item.whatsapp,
  vagas_ids: item.vagas.map(v => v.id),
  message: msg
};

// Grava multiplos logs de disparos (um para cada vaga enviada no resumo)
const data = $node["Simular WhatsApp Diário"].json;
const queries = data.vagas_ids.map(vagaId => {
  return {
    json: {
      query: `INSERT INTO disparos_whatsapp (usuario_id, vaga_id, status_envio, data_envio) VALUES ('${data.usuario_id}'::uuid, '${vagaId}', 'SIMULADO_DIARIO_ENVIADO', NOW());`
    }
  };
});
return queries;
